INSERT INTO dialogues (id, t, tr, icon, cat, lv, turns, sort_order) VALUES
(1, 'Do''konda', 'В магазине', '🛍️', 'Kundalik hayot', 'beginner', '[{"npc": "Здравствуйте! Чем могу помочь?", "npc_uz": "Assalomu alaykum! Sizga qanday yordam bera olaman?", "choices": [{"t": "Здравствуйте! Мне нужен хлеб.", "uz": "Assalomu alaykum! Menga non kerak.", "ok": true, "fb": "To''g''ri — kirib darhol nima kerakligini aytish odob hisoblanadi."}, {"t": "До свидания!", "uz": "Xayr!", "ok": false, "fb": "Suhbat hali boshlanmagan, xayrlashish erta."}, {"t": "Я не знаю.", "uz": "Bilmayman.", "ok": false, "fb": "Bu javob savdogarga hech narsa anglatmaydi."}]}, {"npc": "Сколько вам нужно?", "npc_uz": "Sizga qancha kerak?", "choices": [{"t": "Одну булку, пожалуйста.", "uz": "Bitta non, iltimos.", "ok": true, "fb": "Aniq miqdorni aytish — eng to''g''ri javob."}, {"t": "Не работает.", "uz": "Ishlamayapti.", "ok": false, "fb": "Bu iboraning suhbatga aloqasi yo''q."}, {"t": "Спасибо большое!", "uz": "Katta rahmat!", "ok": false, "fb": "Hali savol javobsiz qoldi."}]}, {"npc": "Что-нибудь ещё?", "npc_uz": "Yana biror narsa kerakmi?", "choices": [{"t": "Да, дайте молоко, пожалуйста.", "uz": "Ha, sut ham bering, iltimos.", "ok": true, "fb": "Qo''shimcha buyurtma berishning tabiiy usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": true, "fb": "Xaridni yakunlash uchun ham to''g''ri javob."}, {"t": "Как дела?", "uz": "Ishlar qalay?", "ok": false, "fb": "Bu savol savdo kontekstiga mos emas."}]}, {"npc": "Итого триста рублей.", "npc_uz": "Jami uch yuz rubl.", "choices": [{"t": "Вот, пожалуйста.", "uz": "Mana, marhamat.", "ok": true, "fb": "Pul to''lashda ishlatiladigan tabiiy ibora."}, {"t": "Это очень вкусно!", "uz": "Bu juda mazali!", "ok": false, "fb": "Hali hech narsa yemadingiz, bu javob mos emas."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari savol."}]}, {"npc": "Спасибо за покупку, всего доброго!", "npc_uz": "Xarid uchun rahmat, hammasi yaxshi bo''lsin!", "choices": [{"t": "Спасибо, до свидания!", "uz": "Rahmat, xayr!", "ok": true, "fb": "Suhbatni yakunlashning eng to''g''ri usuli."}, {"t": "Мне нужно ещё хлеб.", "uz": "Menga yana non kerak.", "ok": false, "fb": "Xarid allaqachon yakunlangan."}, {"t": "Извините, повторите.", "uz": "Kechirasiz, qaytaring.", "ok": false, "fb": "Bu yerda tushunmovchilik yo''q, qayta so''rash keraksiz."}]}]'::jsonb, 1),
(2, 'Kafeda', 'В кафе', '☕', 'Ovqatlanish', 'beginner', '[{"npc": "Добрый день! Что будете заказывать?", "npc_uz": "Xayrli kun! Nima buyurtma qilasiz?", "choices": [{"t": "Добрый день! Кофе с молоком, пожалуйста.", "uz": "Xayrli kun! Sutli qahva, iltimos.", "ok": true, "fb": "Salomlashib, aniq buyurtma berish eng to''g''ri yo''l."}, {"t": "Нет, спасибо.", "uz": "Yo''q, rahmat.", "ok": false, "fb": "Siz kafega kirdingiz, biror narsa buyurtma qilish tabiiy."}, {"t": "Где туалет?", "uz": "Hojatxona qayerda?", "ok": false, "fb": "Avval buyurtma berish, keyin boshqa savollar berish yaxshiroq."}]}, {"npc": "С сахаром или без?", "npc_uz": "Shakar bilanmi yoki shakarsizmi?", "choices": [{"t": "Без сахара, пожалуйста.", "uz": "Shakarsiz, iltimos.", "ok": true, "fb": "To''g''ridan-to''g''ri va aniq javob."}, {"t": "Да.", "uz": "Ha.", "ok": false, "fb": "Bu savolga ''ha'' yoki ''yo''q'' bilan javob berib bo''lmaydi, aniqlashtirish kerak."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas javob."}]}, {"npc": "Что-нибудь поесть хотите?", "npc_uz": "Ovqatdan biror narsa xohlaysizmi?", "choices": [{"t": "Да, один круассан, пожалуйста.", "uz": "Ha, bitta kruassan, iltimos.", "ok": true, "fb": "Aniq buyurtma berishning to''g''ri usuli."}, {"t": "Нет, только кофе.", "uz": "Yo''q, faqat qahva.", "ok": true, "fb": "Aniq va tushunarli rad javobi ham to''g''ri hisoblanadi."}, {"t": "Сколько стоит билет?", "uz": "Chipta qancha turadi?", "ok": false, "fb": "Bu savol kafega aloqasi yo''q."}]}, {"npc": "Хорошо, ждите немного.", "npc_uz": "Yaxshi, biroz kuting.", "choices": [{"t": "Хорошо, спасибо!", "uz": "Yaxshi, rahmat!", "ok": true, "fb": "Kutishga rozilik bildirishning tabiiy javobi."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas, bu ibora mos kelmaydi."}, {"t": "Это очень плохо.", "uz": "Bu juda yomon.", "ok": false, "fb": "Salbiy javob bu holatga mos emas."}]}, {"npc": "Вот ваш кофе. Приятного аппетита!", "npc_uz": "Mana qahvangiz. Yoqimli ishtaha!", "choices": [{"t": "Спасибо большое!", "uz": "Katta rahmat!", "ok": true, "fb": "Minnatdorchilik bildirishning to''g''ri usuli."}, {"t": "Это не моё.", "uz": "Bu meniki emas.", "ok": false, "fb": "Siz buyurtma qilgan edingiz, bu javob noto''g''ri."}, {"t": "До свидания, я не хочу.", "uz": "Xayr, xohlamayman.", "ok": false, "fb": "Buyurtma allaqachon berilgan, rad etish mantiqsiz."}]}]'::jsonb, 2),
(3, 'Restoranda', 'В ресторане', '🍽️', 'Ovqatlanish', 'elementary', '[{"npc": "Добрый вечер! Столик на скольких?", "npc_uz": "Xayrli kech! Nechta kishilik stol kerak?", "choices": [{"t": "Добрый вечер! Столик на двоих, пожалуйста.", "uz": "Xayrli kech! Ikki kishilik stol, iltimos.", "ok": true, "fb": "Kelganda kishilar sonini aytish standart odob."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Siz hali kirib kelyapsiz, xayrlashish erta."}, {"t": "Я не понимаю.", "uz": "Tushunmayapman.", "ok": false, "fb": "Savol sodda, tushunmaslikka hojat yo''q."}]}, {"npc": "Вот меню. Что вы рекомендуете... ой, что будете заказывать?", "npc_uz": "Mana menyu. Nima buyurtma qilasiz?", "choices": [{"t": "Что вы порекомендуете?", "uz": "Nima tavsiya qilasiz?", "ok": true, "fb": "Ofitsiantdan maslahat so''rash tabiiy va foydali."}, {"t": "Дайте мне воды.", "uz": "Menga suv bering.", "ok": false, "fb": "Bu boshqa vaqtda so''raladigan alohida so''rov."}, {"t": "Сколько стоит билет?", "uz": "Chipta qancha turadi?", "ok": false, "fb": "Restoranga aloqasi yo''q savol."}]}, {"npc": "Рекомендую плов, он у нас очень вкусный.", "npc_uz": "Palov tavsiya qilaman, u bizda juda mazali.", "choices": [{"t": "Хорошо, один плов, пожалуйста.", "uz": "Yaxshi, bitta palov, iltimos.", "ok": true, "fb": "Tavsiyani qabul qilib buyurtma berish."}, {"t": "Нет, это плохо.", "uz": "Yo''q, bu yomon.", "ok": false, "fb": "Hali taom kelmagan, salbiy fikr bildirish erta."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Что будете пить?", "npc_uz": "Nima ichasiz?", "choices": [{"t": "Чай, пожалуйста, без сахара.", "uz": "Choy, iltimos, shakarsiz.", "ok": true, "fb": "Ichimlik buyurtmasi aniq va to''g''ri berilgan."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda holat emas."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Taom hali kelmagan, bu javob vaqtidan oldin."}]}, {"npc": "Приятного аппетита! Счёт принести сразу или позже?", "npc_uz": "Yoqimli ishtaha! Hisobni darhol olib kelaymi yoki keyinroq?", "choices": [{"t": "Позже, спасибо.", "uz": "Keyinroq, rahmat.", "ok": true, "fb": "Vaqtni belgilashning odobli usuli."}, {"t": "Счёт, пожалуйста, прямо сейчас.", "uz": "Hisob, iltimos, hozirning o''zida.", "ok": true, "fb": "Bu ham to''g''ri va aniq javob."}, {"t": "Это не моё.", "uz": "Bu meniki emas.", "ok": false, "fb": "Buyurtma o''zingizniki edi, bu javob mantiqsiz."}]}]'::jsonb, 3),
(4, 'Taksida', 'В такси', '🚕', 'Transport', 'elementary', '[{"npc": "Здравствуйте! Куда едем?", "npc_uz": "Assalomu alaykum! Qayerga boramiz?", "choices": [{"t": "Здравствуйте! Мне нужно на вокзал.", "uz": "Assalomu alaykum! Menga vokzalga kerak.", "ok": true, "fb": "Manzilni aniq aytish eng to''g''ri javob."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Safar hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Хорошо, это займёт примерно двадцать минут.", "npc_uz": "Yaxshi, bu taxminan yigirma daqiqa vaqt oladi.", "choices": [{"t": "Хорошо, спасибо.", "uz": "Yaxshi, rahmat.", "ok": true, "fb": "Ma''lumotni qabul qilishning tabiiy javobi."}, {"t": "Нет, это далеко.", "uz": "Yo''q, bu uzoq.", "ok": false, "fb": "Haydovchi faqat vaqtni aytdi, rad etishga hojat yo''q."}, {"t": "Где туалет?", "uz": "Hojatxona qayerda?", "ok": false, "fb": "Mashinada bunday savol berilmaydi."}]}, {"npc": "Можно окно открыть?", "npc_uz": "Derazani ochsam bo''ladimi? (haydovchi so''ramoqda)", "choices": [{"t": "Да, конечно.", "uz": "Ha, albatta.", "ok": true, "fb": "Rozilik bildirishning tabiiy usuli."}, {"t": "Нет, мне холодно.", "uz": "Yo''q, menga sovuq.", "ok": true, "fb": "Sababini aytib rad etish ham to''g''ri va odobli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Bu oddiy savolga mos emas javob."}]}, {"npc": "Приехали, вот вокзал.", "npc_uz": "Keldik, mana vokzal.", "choices": [{"t": "Спасибо! Сколько с меня?", "uz": "Rahmat! Mendan qancha bo''ladi?", "ok": true, "fb": "Yetib kelgach narxni so''rash tabiiy."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Taksida bu ibora mos emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Siz allaqachon yetib keldingiz."}]}, {"npc": "С вас двести рублей.", "npc_uz": "Sizdan ikki yuz rubl.", "choices": [{"t": "Вот, пожалуйста. Сдачи не нужно.", "uz": "Mana, marhamat. Qaytim kerak emas.", "ok": true, "fb": "To''lov qilish va choychaqa haqidagi tabiiy ibora."}, {"t": "Извините, повторите.", "uz": "Kechirasiz, qaytaring.", "ok": false, "fb": "Summa aniq aytilgan, qaytarishga hojat yo''q."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Endi taksidan tushyapsiz, bu savol keraksiz."}]}]'::jsonb, 4),
(5, 'Avtobusda yo''l so''rash', 'В автобусе', '🚌', 'Transport', 'elementary', '[{"npc": "Простите, вам куда нужно?", "npc_uz": "Kechirasiz, sizga qayerga kerak? (yo''lovchi so''ramoqda)", "choices": [{"t": "Мне нужно в центр города.", "uz": "Menga shahar markaziga kerak.", "ok": true, "fb": "Manzilni aniq aytish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmoqda."}, {"t": "Я не знаю.", "uz": "Bilmayman.", "ok": false, "fb": "Bu javob suhbatni davom ettirmaydi."}]}, {"npc": "Тогда вам нужно выйти через три остановки.", "npc_uz": "Unda sizga uch bekatdan keyin tushish kerak.", "choices": [{"t": "Спасибо большое за помощь!", "uz": "Yordamingiz uchun katta rahmat!", "ok": true, "fb": "Yordam uchun minnatdorchilik bildirish to''g''ri."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu ma''lumot foydali, salbiy baho noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Siz allaqachon avtobusdasiz."}]}, {"npc": "Не за что. Вы турист?", "npc_uz": "Arzimaydi. Siz turistmisiz?", "choices": [{"t": "Нет, я живу здесь.", "uz": "Yo''q, men shu yerda yashayman.", "ok": true, "fb": "Savolga to''g''ridan-to''g''ri javob."}, {"t": "Да, я турист.", "uz": "Ha, men turistman.", "ok": true, "fb": "Bu ham to''g''ri, holatga qarab ikkalasi ham mumkin."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Понятно! Вот ваша остановка.", "npc_uz": "Tushunarli! Mana sizning bekatingiz.", "choices": [{"t": "Спасибо, до свидания!", "uz": "Rahmat, xayr!", "ok": true, "fb": "Tushishdan oldin xayrlashish odobli."}, {"t": "Мне нужно на вокзал.", "uz": "Menga vokzalga kerak.", "ok": false, "fb": "Endi tushish kerak, yangi manzil aytish o''rinsiz."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Счастливого пути!", "npc_uz": "Yaxshi yo''l tilayman!", "choices": [{"t": "Спасибо, взаимно!", "uz": "Rahmat, sizga ham!", "ok": true, "fb": "Yaxshi tilaklarga javob berishning odobli usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu ibora bu holatga mos emas."}, {"t": "Где банкомат?", "uz": "Bankomat qayerda?", "ok": false, "fb": "Suhbat allaqachon yakunlanmoqda."}]}]'::jsonb, 5),
(6, 'Klinikada', 'В поликлинике', '🏥', 'Salomatlik', 'intermediate', '[{"npc": "Здравствуйте! На что жалуетесь?", "npc_uz": "Assalomu alaykum! Nimadan shikoyat qilyapsiz?", "choices": [{"t": "Здравствуйте! У меня температура и болит горло.", "uz": "Assalomu alaykum! Menda isitma va tomog''im og''riyapti.", "ok": true, "fb": "Shifokorga aniq shikoyat aytish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Qabul hali boshlanmagan."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Klinikada bu ibora mos emas."}]}, {"npc": "Как давно это началось?", "npc_uz": "Bu qachondan boshlangan?", "choices": [{"t": "Два дня назад.", "uz": "Ikki kun oldin.", "ok": true, "fb": "Aniq vaqtni aytish shifokorga foydali."}, {"t": "Не знаю, помогите!", "uz": "Bilmayman, yordam bering!", "ok": false, "fb": "Bu vaziyat favqulodda emas, aniqroq javob kerak."}, {"t": "Где посольство?", "uz": "Elchixona qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "У вас есть аллергия на лекарства?", "npc_uz": "Dorilarga allergiyangiz bormi?", "choices": [{"t": "Нет, аллергии нет.", "uz": "Yo''q, allergiya yo''q.", "ok": true, "fb": "Muhim tibbiy ma''lumotga aniq javob."}, {"t": "Да, я аллергик.", "uz": "Ha, menda allergiya bor.", "ok": true, "fb": "Bu ham to''g''ri javob, agar rost bo''lsa."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Savolga javob emas."}]}, {"npc": "Хорошо, я выпишу вам рецепт.", "npc_uz": "Yaxshi, men sizga retsept yozib beraman.", "choices": [{"t": "Спасибо. Как принимать лекарство?", "uz": "Rahmat. Dorini qanday ichish kerak?", "ok": true, "fb": "Qo''llanma so''rash muhim va to''g''ri."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Retsept haqida ma''lumot olish kerak."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Bu holatga mos emas ibora."}]}, {"npc": "Два раза в день после еды. Выздоравливайте!", "npc_uz": "Kuniga ikki marta ovqatdan keyin. Tuzalib keting!", "choices": [{"t": "Спасибо большое, до свидания!", "uz": "Katta rahmat, xayr!", "ok": true, "fb": "Qabulni yakunlashning odobli usuli."}, {"t": "Сколько стоит билет?", "uz": "Chipta qancha turadi?", "ok": false, "fb": "Mavzuga mos emas."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Klinikaga mos kelmaydigan ibora."}]}]'::jsonb, 6),
(7, 'Aptekada', 'В аптеке', '💊', 'Salomatlik', 'intermediate', '[{"npc": "Здравствуйте! Что вам нужно?", "npc_uz": "Assalomu alaykum! Sizga nima kerak?", "choices": [{"t": "Здравствуйте! Мне нужно что-то от простуды.", "uz": "Assalomu alaykum! Menga shamollashdan biror narsa kerak.", "ok": true, "fb": "Kerakli dori turini aniq aytish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmagan."}, {"t": "Я не знаю.", "uz": "Bilmayman.", "ok": false, "fb": "Bu javob farmatsevtga yordam bermaydi."}]}, {"npc": "У вас есть температура?", "npc_uz": "Isitmangiz bormi?", "choices": [{"t": "Да, температура тридцать восемь.", "uz": "Ha, isitma o''ttiz sakkiz.", "ok": true, "fb": "Aniq ma''lumot berish to''g''ri."}, {"t": "Нет, только кашель.", "uz": "Yo''q, faqat yo''talim bor.", "ok": true, "fb": "Bu ham to''g''ri va aniq javob."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda holat emas."}]}, {"npc": "Вот таблетки. По одной три раза в день.", "npc_uz": "Mana tabletkalar. Kuniga uch marta bittadan.", "choices": [{"t": "Спасибо. По рецепту врача нужны?", "uz": "Rahmat. Shifokor retsepti kerakmi?", "ok": true, "fb": "Muhim savol, aniqlashtirish to''g''ri."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Farmatsevt yordam berdi, bu javob noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Нет, эти без рецепта.", "npc_uz": "Yo''q, bular retseptsiz sotiladi.", "choices": [{"t": "Хорошо, сколько стоит?", "uz": "Yaxshi, qancha turadi?", "ok": true, "fb": "Narx so''rash tabiiy davomi."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Narx hali aytilmagan."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Сто пятьдесят рублей. Проверьте срок годности.", "npc_uz": "Bir yuz ellik rubl. Yaroqlilik muddatini tekshiring.", "choices": [{"t": "Хорошо, спасибо за совет!", "uz": "Yaxshi, maslahat uchun rahmat!", "ok": true, "fb": "Foydali maslahatga minnatdorchilik bildirish to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Aptekaga mos emas savol."}]}]'::jsonb, 7),
(8, 'Mehmonxonada', 'В гостинице', '🏨', 'Turar joy', 'intermediate', '[{"npc": "Добрый день! У вас забронирован номер?", "npc_uz": "Xayrli kun! Sizda xona bron qilinganmi?", "choices": [{"t": "Добрый день! Да, номер на моё имя.", "uz": "Xayrli kun! Ha, mening ismimga xona bor.", "ok": true, "fb": "Bron borligini tasdiqlash to''g''ri javob."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Ro''yxatdan o''tish hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Ваш паспорт, пожалуйста.", "npc_uz": "Pasportingiz, iltimos.", "choices": [{"t": "Вот мой паспорт.", "uz": "Mana mening pasportim.", "ok": true, "fb": "Hujjat taqdim etishning to''g''ri usuli."}, {"t": "Нет, спасибо.", "uz": "Yo''q, rahmat.", "ok": false, "fb": "Bu hujjat talab qilinadi, rad etib bo''lmaydi."}, {"t": "Где туалет?", "uz": "Hojatxona qayerda?", "ok": false, "fb": "Vaqti kelmagan savol."}]}, {"npc": "Завтрак включён, он с семи до десяти.", "npc_uz": "Nonushta kiritilgan, u ettidan o''ngacha.", "choices": [{"t": "Спасибо за информацию!", "uz": "Ma''lumot uchun rahmat!", "ok": true, "fb": "Ma''lumotga minnatdorchilik bildirish to''g''ri."}, {"t": "Это очень плохо.", "uz": "Bu juda yomon.", "ok": false, "fb": "Bu foydali ma''lumot, salbiy javob noto''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Вот ключ от номера, третий этаж.", "npc_uz": "Mana xona kaliti, uchinchi qavat.", "choices": [{"t": "Спасибо! А Wi-Fi пароль есть?", "uz": "Rahmat! Wi-Fi paroli bormi?", "ok": true, "fb": "Qo''shimcha so''rash tabiiy davomi."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": true, "fb": "Suhbatni yakunlash ham to''g''ri variant."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mehmonxonaga mos emas savol."}]}, {"npc": "Конечно, пароль на карточке в номере.", "npc_uz": "Albatta, parol xonadagi kartochkada.", "choices": [{"t": "Отлично, спасибо большое!", "uz": "Ajoyib, katta rahmat!", "ok": true, "fb": "Minnatdorchilik bildirishning tabiiy yakuni."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Ma''lumot foydali, salbiy javob mos emas."}, {"t": "Где банкомат?", "uz": "Bankomat qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}]'::jsonb, 8),
(9, 'Bankda', 'В банке', '🏦', 'Moliya', 'intermediate', '[{"npc": "Здравствуйте! Чем могу помочь?", "npc_uz": "Assalomu alaykum! Sizga qanday yordam bera olaman?", "choices": [{"t": "Здравствуйте! Я хочу открыть счёт.", "uz": "Assalomu alaykum! Men hisob ochmoqchiman.", "ok": true, "fb": "Maqsadni aniq aytish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmagan."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Bankka mos emas ibora."}]}, {"npc": "Хорошо, нужен ваш паспорт.", "npc_uz": "Yaxshi, pasportingiz kerak.", "choices": [{"t": "Вот мой паспорт, пожалуйста.", "uz": "Mana mening pasportim, marhamat.", "ok": true, "fb": "Hujjatni taqdim etish to''g''ri."}, {"t": "Нет, спасибо.", "uz": "Yo''q, rahmat.", "ok": false, "fb": "Hujjat talab qilinmoqda, rad etib bo''lmaydi."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Какая комиссия вас интересует, знаете?", "npc_uz": "Qanday komissiya sizni qiziqtiradi, bilasizmi? (menejer aniqlashtirmoqda)", "choices": [{"t": "Какая у вас комиссия за обслуживание?", "uz": "Xizmat ko''rsatish uchun komissiyangiz qancha?", "ok": true, "fb": "Muhim savolni aniq berish to''g''ri."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Hali javob olinmagan, baho berish erta."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Комиссии нет в первый год.", "npc_uz": "Birinchi yilda komissiya yo''q.", "choices": [{"t": "Отлично, это мне подходит.", "uz": "Ajoyib, bu menga mos.", "ok": true, "fb": "Ijobiy javob berishning tabiiy usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu yaxshi shart, rad etish mantiqsiz."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Отлично, подпишите здесь, пожалуйста.", "npc_uz": "Ajoyib,