(10, 'Aeroportda', 'В аэропорту', '✈️', 'Transport', 'upper', '[{"npc": "Добрый день! Ваш паспорт и билет, пожалуйста.", "npc_uz": "Xayrli kun! Pasportingiz va chiptangiz, iltimos.", "choices": [{"t": "Добрый день! Вот мой паспорт и билет.", "uz": "Xayrli kun! Mana mening pasportim va chiptam.", "ok": true, "fb": "Hujjatlarni taqdim etishning to''g''ri usuli."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Ro''yxatdan o''tish hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Место у окна или у прохода?", "npc_uz": "Deraza yonidami yoki yo''lak yonidami?", "choices": [{"t": "Место у окна, пожалуйста.", "uz": "Deraza yonidagi joy, iltimos.", "ok": true, "fb": "Aniq tanlov qilish to''g''ri."}, {"t": "Место у прохода, пожалуйста.", "uz": "Yo''lak yonidagi joy, iltimos.", "ok": true, "fb": "Bu ham to''g''ri, ikkala tanlov ham mumkin."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Сколько у вас багажа?", "npc_uz": "Sizda qancha yuk bor?", "choices": [{"t": "У меня один чемодан.", "uz": "Menda bitta chamadon bor.", "ok": true, "fb": "Aniq javob berish to''g''ri."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Aeroportga mos emas ibora."}, {"t": "Где посольство?", "uz": "Elchixona qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Хорошо, ваш рейс задерживается на тридцать минут.", "npc_uz": "Yaxshi, sizning reysingiz o''ttiz daqiqaga kechikmoqda.", "choices": [{"t": "Спасибо, что сообщили.", "uz": "Xabar berganingiz uchun rahmat.", "ok": true, "fb": "Ma''lumotga minnatdorchilik bildirish to''g''ri."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu holatga mos kelmaydigan javob."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Aeroportga mos emas savol."}]}, {"npc": "Приятного полёта!", "npc_uz": "Yoqimli parvoz!", "choices": [{"t": "Спасибо, до свидания!", "uz": "Rahmat, xayr!", "ok": true, "fb": "Yaxshi tilakka javob berishning odobli usuli."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu yaxshi tilak, salbiy javob noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Aeroportda mos emas savol."}]}]'::jsonb, 10),
(11, 'Ish suhbati (intervyu)', 'Собеседование', '💼', 'Ish', 'upper', '[{"npc": "Здравствуйте! Расскажите о себе.", "npc_uz": "Assalomu alaykum! O''zingiz haqingizda gapirib bering.", "choices": [{"t": "Здравствуйте! Я студент и ищу работу.", "uz": "Assalomu alaykum! Men talabaman va ish qidiryapman.", "ok": true, "fb": "O''zi haqida qisqa va aniq gapirish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Intervyu hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Savolga javob emas."}]}, {"npc": "Какой у вас опыт работы?", "npc_uz": "Ish tajribangiz qancha?", "choices": [{"t": "У меня два года опыта.", "uz": "Mening ikki yillik tajribam bor.", "ok": true, "fb": "Aniq javob berish to''g''ri."}, {"t": "У меня нет опыта, но я хочу учиться.", "uz": "Tajribam yo''q, lekin o''rganishni xohlayman.", "ok": true, "fb": "Bu ham halol va to''g''ri javob."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Какая зарплата вас интересует?", "npc_uz": "Qanday maosh sizni qiziqtiradi?", "choices": [{"t": "Это зависит от условий работы.", "uz": "Bu ish shartlariga bog''liq.", "ok": true, "fb": "Diplomatik va professional javob."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Intervyuga mos emas ibora."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Когда вы можете начать работать?", "npc_uz": "Qachon ishni boshlashingiz mumkin?", "choices": [{"t": "Я могу начать через неделю.", "uz": "Men bir haftadan keyin boshlashim mumkin.", "ok": true, "fb": "Aniq vaqt aytish to''g''ri."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu savolga mos emas javob."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Спасибо, мы свяжемся с вами.", "npc_uz": "Rahmat, biz siz bilan bog''lanamiz.", "choices": [{"t": "Спасибо большое за возможность!", "uz": "Imkoniyat uchun katta rahmat!", "ok": true, "fb": "Intervyuni yakunlashning odobli usuli."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu yaxshi yakun, salbiy javob mos emas."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}]'::jsonb, 11),
(12, 'Telefon orqali gaplashish', 'Разговор по телефону', '📞', 'Kundalik hayot', 'elementary', '[{"npc": "Алло! Слушаю вас.", "npc_uz": "Alo! Tinglayapman.", "choices": [{"t": "Здравствуйте! Это Азиз. Можно Анну?", "uz": "Assalomu alaykum! Bu Aziz. Annani chaqirsam bo''ladimi?", "ok": true, "fb": "O''zini tanishtirib, kerakli odamni so''rash to''g''ri."}, {"t": "До свидания!", "uz": "Xayr!", "ok": false, "fb": "Suhbat hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Извините, её сейчас нет. Что-нибудь передать?", "npc_uz": "Kechirasiz, u hozir yo''q. Biror narsa yetkazib qo''yaymi?", "choices": [{"t": "Да, передайте, что звонил Азиз.", "uz": "Ha, Aziz qo''ng''iroq qilgan deb ayting.", "ok": true, "fb": "Xabar qoldirishning to''g''ri usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": true, "fb": "Xabarsiz qo''yish ham to''g''ri variant."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Хорошо, я передам. Что-нибудь ещё?", "npc_uz": "Yaxshi, yetkazaman. Yana biror narsa bormi?", "choices": [{"t": "Нет, спасибо большое.", "uz": "Yo''q, katta rahmat.", "ok": true, "fb": "Suhbatni yakunlashning to''g''ri usuli."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Telefon suhbatiga mos emas."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Хорошо, всего доброго!", "npc_uz": "Yaxshi, hammasi yaxshi bo''lsin!", "choices": [{"t": "Спасибо, до свидания!", "uz": "Rahmat, xayr!", "ok": true, "fb": "Telefon suhbatini yakunlash to''g''ri."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzuga mos emas savol."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu yaxshi yakun, salbiy javob noto''g''ri."}]}, {"npc": "[Qo''ng''iroq tugadi]", "npc_uz": "[Qo''ng''iroq tugadi]", "choices": [{"t": "Отлично, спасибо за разговор!", "uz": "Ajoyib, suhbat uchun rahmat!", "ok": true, "fb": "Yakuniy fikr sifatida tabiiy javob."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Suhbat muvaffaqiyatli o''tdi, salbiy baho noto''g''ri."}]}]'::jsonb, 12),
(13, 'Ko''chada yo''l so''rash', 'Как пройти?', '🗺️', 'Kundalik hayot', 'beginner', '[{"npc": "Слушаю вас.", "npc_uz": "Tinglayapman. (yo''lovchi javob berdi)", "choices": [{"t": "Извините, где находится метро?", "uz": "Kechirasiz, metro qayerda joylashgan?", "ok": true, "fb": "Odob bilan savol berishning to''g''ri usuli."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Savol hali berilmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Идите прямо, потом направо.", "npc_uz": "To''g''riga boring, keyin o''ngga.", "choices": [{"t": "Спасибо большое!", "uz": "Katta rahmat!", "ok": true, "fb": "Ko''rsatma uchun minnatdorchilik bildirish to''g''ri."}, {"t": "Нет, это далеко.", "uz": "Yo''q, bu uzoq.", "ok": false, "fb": "Masofa hali aytilmagan, bu javob noto''rin."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Это далеко? Пять минут пешком.", "npc_uz": "Bu uzoqmi? Piyoda besh daqiqa.", "choices": [{"t": "Отлично, это близко!", "uz": "Ajoyib, bu yaqin ekan!", "ok": true, "fb": "Ma''lumotga tabiiy munosabat bildirish."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas ibora."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Siz piyoda ketyapsiz, bu savol mos emas."}]}, {"npc": "Не за что. Удачи!", "npc_uz": "Arzimaydi. Omad!", "choices": [{"t": "Спасибо, взаимно!", "uz": "Rahmat, sizga ham!", "ok": true, "fb": "Yaxshi tilakka javob berishning odobli usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu ibora bu holatga mos emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu yaxshi tilak, salbiy javob noto''g''ri."}]}, {"npc": "[Siz metroni topdingiz]", "npc_uz": "[Siz metroni topdingiz]", "choices": [{"t": "Наконец-то нашёл, спасибо ему!", "uz": "Nihoyat topdim, unga rahmat!", "ok": true, "fb": "Vaziyatni yakunlovchi tabiiy fikr."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Siz maqsadga erishdingiz, salbiy javob mos emas."}]}]'::jsonb, 13),
(14, 'Yangi tanish bilan suhbat', 'Знакомство', '🤝', 'Kundalik hayot', 'beginner', '[{"npc": "Здравствуйте! Как вас зовут?", "npc_uz": "Assalomu alaykum! Ismingiz nima?", "choices": [{"t": "Здравствуйте! Меня зовут Дилноза.", "uz": "Assalomu alaykum! Mening ismim Dilnoza.", "ok": true, "fb": "Ismni aytishning to''g''ri usuli."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Tanishuv hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Приятно познакомиться! Откуда вы?", "npc_uz": "Tanishganimdan xursandman! Siz qayerdansiz?", "choices": [{"t": "Я из Ташкента.", "uz": "Men Toshkentdanman.", "ok": true, "fb": "Kelib chiqishni aytishning to''g''ri usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Где банкомат?", "uz": "Bankomat qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "О, красивый город! Вы здесь живёте?", "npc_uz": "Voy, chiroyli shahar! Siz shu yerda yashaysizmi?", "choices": [{"t": "Да, я живу в Ташкенте уже пять лет.", "uz": "Ha, men Toshkentda besh yildan beri yashayman.", "ok": true, "fb": "Aniq va batafsil javob to''g''ri."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Bu suhbatga aloqasi yo''q."}]}, {"npc": "Чем вы занимаетесь?", "npc_uz": "Siz nima bilan shug''ullanasiz?", "choices": [{"t": "Я студент, изучаю русский язык.", "uz": "Men talabaman, rus tilini o''rganaman.", "ok": true, "fb": "Kasb/faoliyat haqida aniq javob."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Savolga mos emas javob."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Savolga javob emas."}]}, {"npc": "Здорово! Было приятно познакомиться.", "npc_uz": "Ajoyib! Tanishganimdan xursand bo''ldim.", "choices": [{"t": "Мне тоже очень приятно!", "uz": "Menga ham juda yoqdi!", "ok": true, "fb": "Iliq tarzda suhbatni yakunlash."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu ijobiy yakun, salbiy javob noto''g''ri."}]}]'::jsonb, 14),
(15, 'Ob-havo haqida suhbat', 'О погоде', '☀️', 'Kundalik hayot', 'beginner', '[{"npc": "Какая сегодня хорошая погода, правда?", "npc_uz": "Bugun ob-havo naqadar yaxshi, shundaymi?", "choices": [{"t": "Да, светит солнце и тепло.", "uz": "Ha, quyosh chiqmoqda va issiq.", "ok": true, "fb": "Ob-havo haqida tasdiqlovchi javob."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali davom etmoqda."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Suhbatdosh ijobiy fikr bildirdi."}]}, {"npc": "А вчера было холодно и дождливо.", "npc_uz": "Kecha esa sovuq va yomg''irli edi.", "choices": [{"t": "Да, вчера было очень холодно.", "uz": "Ha, kecha juda sovuq edi.", "ok": true, "fb": "Suhbatdosh fikriga qo''shilish to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Вы любите зиму или лето?", "npc_uz": "Siz qishni yoqtirasizmi yoki yozni?", "choices": [{"t": "Я люблю лето, потому что тепло.", "uz": "Men yozni yoqtiraman, chunki issiq bo''ladi.", "ok": true, "fb": "Shaxsiy fikr bildirishning to''g''ri usuli."}, {"t": "Я люблю зиму, потому что красиво.", "uz": "Men qishni yoqtiraman, chunki chiroyli bo''ladi.", "ok": true, "fb": "Bu ham to''g''ri shaxsiy fikr."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Согласен! Вы смотрели прогноз на завтра?", "npc_uz": "Roziman! Ertangi ob-havo bashoratini ko''rdingizmi?", "choices": [{"t": "Да, завтра будет дождь.", "uz": "Ha, ertaga yomg''ir bo''ladi.", "ok": true, "fb": "Aniq ma''lumot berish to''g''ri."}, {"t": "Нет, не смотрел.", "uz": "Yo''q, ko''rmadim.", "ok": true, "fb": "Halol javob berish ham to''g''ri."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Тогда возьмите зонт с собой!", "npc_uz": "Unda o''zingiz bilan soyabon oling!", "choices": [{"t": "Хорошо, спасибо за совет!", "uz": "Yaxshi, maslahat uchun rahmat!", "ok": true, "fb": "Foydali maslahatga minnatdorchilik bildirish."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu foydali maslahat, salbiy javob noto''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}]'::jsonb, 15),
(16, 'Sartaroshxonada', 'В парикмахерской', '💇', 'Kundalik hayot', 'elementary', '[{"npc": "Здравствуйте! Что будем делать?", "npc_uz": "Assalomu alaykum! Nima qilamiz?", "choices": [{"t": "Здравствуйте! Постригите меня, пожалуйста.", "uz": "Assalomu alaykum! Sochimni oling, iltimos.", "ok": true, "fb": "Xizmatni aniq so''rash to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Xizmat hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Как коротко подстричь?", "npc_uz": "Qanchalik qisqa olay?", "choices": [{"t": "Не очень коротко, пожалуйста.", "uz": "Juda qisqa emas, iltimos.", "ok": true, "fb": "Aniq talab bildirish to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Хорошо. Вам нравится?", "npc_uz": "Yaxshi. Sizga yoqdimi? (ish jarayonida so''ramoqda)", "choices": [{"t": "Да, мне очень нравится, спасибо.", "uz": "Ha, menga juda yoqdi, rahmat.", "ok": true, "fb": "Ijobiy fikr bildirishning tabiiy usuli."}, {"t": "Нет, это плохо.", "uz": "Yo''q, bu yomon.", "ok": true, "fb": "Agar rost bo''lsa, bu ham halol javob."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Sartaroshxonaga mos emas ibora."}]}, {"npc": "Итого триста рублей.", "npc_uz": "Jami uch yuz rubl.", "choices": [{"t": "Вот, пожалуйста.", "uz": "Mana, marhamat.", "ok": true, "fb": "To''lov qilishning tabiiy usuli."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Xizmat yaxshi bajarildi, salbiy javob noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Спасибо, приходите ещё!", "npc_uz": "Rahmat, yana kelib turing!", "choices": [{"t": "Обязательно приду, спасибо!", "uz": "Albatta kelaman, rahmat!", "ok": true, "fb": "Iliq yakunlovchi javob."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu holatga mos kelmaydi."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Xizmatdan mamnun bo''ldingiz, bu javob noto''g''ri."}]}]'::jsonb, 16),
(17, 'Kompyuter ustaxonasida', 'В мастерской', '💻', 'Texnologiya', 'upper', '[{"npc": "Здравствуйте! Какая у вас проблема?", "npc_uz": "Assalomu alaykum! Sizda qanday muammo bor?", "choices": [{"t": "Здравствуйте! Компьютер не включается.", "uz": "Assalomu alaykum! Kompyuter yoqilmayapti.", "ok": true, "fb": "Muammoni aniq tasvirlash to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmagan."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Когда это началось?", "npc_uz": "Bu qachondan boshlandi?", "choices": [{"t": "Со вчерашнего дня.", "uz": "Kechadan beri.", "ok": true, "fb": "Aniq vaqt aytish to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Понятно, я посмотрю. Оставите компьютер?", "npc_uz": "Tushunarli, men ko''rib chiqaman. Kompyuterni qoldirasizmi?", "choices": [{"t": "Да, конечно, оставлю.", "uz": "Ha, albatta, qoldiraman.", "ok": true, "fb": "Rozilik bildirishning to''g''ri usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Ustaxonaga topshirish kerak, bu javob mos emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Usta yordam bermoqchi, salbiy javob noto''g''ri."}]}, {"npc": "Хорошо, будет готово завтра.", "npc_uz": "Yaxshi, ertaga tayyor bo''ladi.", "choices": [{"t": "Сколько это будет стоить?", "uz": "Bu qancha turadi?", "ok": true, "fb": "Narx so''rash tabiiy davomi."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Ustaxonaga mos emas savol."}]}, {"npc": "Примерно пятьсот рублей.", "npc_uz": "Taxminan besh yuz rubl.", "choices": [{"t": "Хорошо, спасибо, приду завтра.", "uz": "Yaxshi, rahmat, ertaga kelaman.", "ok": true, "fb": "Kelishuvni yakunlashning to''g''ri usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Narx aniq aytildi, salbiy javob noto''g''ri."}]}]'::jsonb, 17),
(18, 'Bozorda savdolashish', 'На рынке', '🛒', 'Ovqatlanish', 'elementary', '[{"npc": "Здравствуйте! Свежие яблоки, покупайте!", "npc_uz": "Assalomu alaykum! Yangi olmalar, sotib oling!", "choices": [{"t": "Здравствуйте! Сколько стоит килограмм?", "uz": "Assalomu alaykum! Bir kilogrammi qancha turadi?", "ok": true, "fb": "Narx so''rashning to''g''ri usuli."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Savdo hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mahsulotni ko''rmasdan baho berish noto''g''ri."}]}, {"npc": "Сто рублей за килограмм.", "npc_uz": "Bir kilogrammi yuz rubl.", "choices": [{"t": "Это дорого, можно дешевле?", "uz": "Bu qimmat, arzonroq bo''ladimi?", "ok": true, "fb": "Savdolashishning odatiy va to''g''ri usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Хорошо, для вас восемьдесят рублей.", "npc_uz": "Yaxshi, siz uchun sakson rubl.", "choices": [{"t": "Хорошо, я беру два килограмма.", "uz": "Yaxshi, men ikki kilogramm olaman.", "ok": true, "fb": "Kelishuvga rozilik bildirib buyurtma berish."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": true, "fb": "Xarid qilmaslikka qaror qilish ham to''g''ri variant."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Hali tatib ko''rmadingiz."}]}, {"npc": "Вот, пожалуйста. Ещё что-нибудь?", "npc_uz": "Mana, marhamat. Yana biror narsa kerakmi?", "choices": [{"t": "Да, дайте ещё помидоры.", "uz": "Ha, pomidor ham bering.", "ok": true, "fb": "Qo''shimcha buyurtma berish tabiiy."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": true, "fb": "Xaridni yakunlash ham to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}]}, {"npc": "Итого сто шестьдесят рублей.", "npc_uz": "Jami bir yuz oltmish rubl.", "choices": [{"t": "Вот, пожалуйста, спасибо!", "uz": "Mana, marhamat, rahmat!", "ok": true, "fb": "To''lov qilib minnatdorchilik bildirish."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Savdo muvaffaqiyatli o''tdi, salbiy javob noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}]'::jsonb, 18),
(19, 'Kiyim-kechak do''konida', 'В магазине одежды', '👕', 'Kundalik hayot', 'beginner', '[{"npc": "Здравствуйте! Ищете что-то конкретное?", "npc_uz": "Assalomu alaykum! Aniq biror narsa qidiryapsizmi?", "choices": [{"t": "Здравствуйте! Я ищу рубашку.", "uz": "Assalomu alaykum! Men ko''ylak qidiryapman.", "ok": true, "fb": "Kerakli mahsulotni aytish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmagan."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Какой размер вам нужен?", "npc_uz": "Sizga qanday o''lcham kerak?", "choices": [{"t": "Мне нужен размер сорок четыре.", "uz": "Menga qirq to''rtinchi o''lcham kerak.", "ok": true, "fb": "Aniq o''lcham aytish to''g''ri."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Вот, можете примерить в примерочной.", "npc_uz": "Mana, kiyinish xonasida o''lchab ko''rishingiz mumkin.", "choices": [{"t": "Хорошо, спасибо.", "uz": "Yaxshi, rahmat.", "ok": true, "fb": "Taklifni qabul qilishning to''g''ri usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Hali o''lchab ko''rmadingiz."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Ну как, подошло?", "npc_uz": "Xo''sh, mos keldimi?", "choices": [{"t": "Да, отлично сидит, беру.", "uz": "Ha, juda yaxshi turibdi, olaman.", "ok": true, "fb": "Ijobiy natija haqida to''g''ri javob."}, {"t": "Нет, слишком мало, дайте больше.", "uz": "Yo''q, juda kichik, kattaroq bering.", "ok": true, "fb": "Muammoni bildirish ham to''g''ri javob."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Aniqroq javob berish kerak edi."}]}, {"npc": "Отлично! Итого пятьсот рублей.", "npc_uz": "Ajoyib! Jami besh yuz rubl.", "choices": [{"t": "Вот, пожалуйста, спасибо!", "uz": "Mana, marhamat, rahmat!", "ok": true, "fb": "To''lov qilishning to''g''ri usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}]'::jsonb, 19),
(20, 'Bayram tabriklash', 'Поздравление с праздником', '🎉', 'Kundalik hayot', 'beginner', '[{"npc": "Здравствуйте! Скоро Новый год!", "npc_uz": "Assalomu alaykum! Tez orada Yangi yil!", "choices": [{"t": "Здравствуйте! Да, я очень жду праздник.", "uz": "Assalomu alaykum! Ha, men bayramni juda kutyapman.", "ok": true, "fb": "Suhbatga tabiiy javob berish to''g''ri."}, {"t": "Спасибо, до свидания.", "uz": "Rahmat, xayr.", "ok": false, "fb": "Suhbat hali boshlanmoqda."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Suhbatdosh xursandchilik bildirdi, salbiy javob noto''g''ri."}]}, {"npc": "Какие у вас планы на праздники?", "npc_uz": "Bayram uchun rejalaringiz qanday?", "choices": [{"t": "Я поеду к семье.", "uz": "Men oilamnikiga boraman.", "ok": true, "fb": "Rejani aytishning to''g''ri usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Куда едем?", "uz": "Qayerga boramiz?", "ok": false, "fb": "Bu javob emas, savolga mos emas."}]}, {"npc": "Здорово! С Новым годом заранее!", "npc_uz": "Ajoyib! Yangi yil bilan oldindan tabriklayman!", "choices": [{"t": "Спасибо! И вас с Новым годом!", "uz": "Rahmat! Sizni ham Yangi yil bilan!", "ok": true, "fb": "Tabrikga javob berishning to''g''ri usuli."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu yaxshi tabrik, salbiy javob noto''g''ri."}, {"t": "Где остановка автобуса?", "uz": "Avtobus bekati qayerda?", "ok": false, "fb": "Mavzudan tashqari."}]}, {"npc": "Желаю вам счастья и здоровья!", "npc_uz": "Sizga baxt va sog''lik tilayman!", "choices": [{"t": "Спасибо большое, взаимно!", "uz": "Katta rahmat, sizga ham!", "ok": true, "fb": "Yaxshi tilaklarga javob berishning odobli usuli."}, {"t": "Нет, спасибо, это всё.", "uz": "Yo''q, rahmat, shu bo''ldi.", "ok": false, "fb": "Bu ibora bu holatga mos emas."}, {"t": "Это очень вкусно.", "uz": "Bu juda mazali.", "ok": false, "fb": "Mavzuga mos emas."}]}, {"npc": "Всего доброго, до встречи!", "npc_uz": "Hammasi yaxshi bo''lsin, ko''rishguncha!", "choices": [{"t": "До свидания, всего хорошего!", "uz": "Xayr, hammasi yaxshi bo''lsin!", "ok": true, "fb": "Xayrlashishning to''g''ri va odobli usuli."}, {"t": "Помогите!", "uz": "Yordam bering!", "ok": false, "fb": "Favqulodda vaziyat emas."}, {"t": "Это плохо.", "uz": "Bu yomon.", "ok": false, "fb": "Bu iliq xayrlashuv, salbiy javob noto''g''ri."}]}]'::jsonb, 20)
