-- Baza: Rus Tili — Dialogue (Suhbat) system migration
-- Run this in Supabase SQL Editor AFTER the main schema.sql has already been applied.
-- This adds: a dialogues table (20 seeded conversations) + a dialogues_done column on users.

create table if not exists dialogues (
  id integer primary key,
  t text not null,
  tr text default '',
  icon text default '💬',
  cat text default '',
  lv text not null,
  turns jsonb not null default '[]',
  sort_order integer not null default 0
);

alter table dialogues enable row level security;
-- (No policies added on purpose — default-deny, same as lessons/users. Service role key bypasses RLS.)

alter table users add column if not exists dialogues_done jsonb not null default '[]';

ON CONFLICT (id) DO NOTHING;
